const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(input[idx++]);
  const X = Number(input[idx++]);
  const a = new Array(N);
  for (let i = 0; i < N; i++) a[i] = Number(input[idx++]);
  const b = [...a].sort((p, q) => p - q);
  let ok = true;
  for (let i = 0; i < N; i++) {
    if (a[i] !== b[i] && (a[i] > X || b[i] > X)) { ok = false; break; }
  }
  out.push(ok ? 'YES' : 'NO');
}
